import java.util.*;

class Node {
    int key, value;
    int count;
    Node prev, next;
    public Node(int key, int value) {
        this.key = key;
        this.value = value;
        this.count = 1;
    }
}

class DoublyLinkedList {
    Node head, tail;
    public void addNode(Node node) {
        if (head == null) {
            head = node;
            tail = node;
        } else {
            node.prev = tail;
            tail.next = node;
            tail = node;
        }
    }

    public void removeNode(Node node) {
        if (node.prev != null) {
            node.prev.next = node.next;
        } else {
            head = node.next;
        }
        if (node.next != null) {
            node.next.prev = node.prev;
        } else {
            tail = node.prev;
        }
    }

    public Node removeHead() {
        Node node = head;
        removeNode(node);
        return node;
    }
}

class LFUCache {

    public LFUCache(int capacity) {
        this.capacity = capacity;
        this.size = 0;
        this.minCount = 0;
        this.cache = new HashMap<>();
        this.freqMap = new HashMap<>();
        this.freqList = new HashMap<>();
    }

    public int get(int key) {
        if (!cache.containsKey(key)) {
            return -1;
        }
        Node node = cache.get(key);
        int count = node.count;
        node.count++;
        freqList.get(count).removeNode(node);
        if (count == minCount && freqList.get(count).size() == 0) {
            minCount++;
        }
        if (!freqList.containsKey(count + 1)) {
            freqList.put(count + 1, new DoublyLinkedList());
        }
        freqList.get(count + 1).addNode(node);
        return node.value;
    }

    public void put(int key, int value) {
        if (capacity == 0) {
            return;
        }
        if (cache.containsKey(key)) {
            Node node = cache.get(key);
            node.value = value;
            int count = node.count;
            node.count++;
            freqList.get(count).removeNode(node);
            if (count == minCount && freqList.get(count).size() == 0) {
                minCount++;
            }
            if (!freqList.containsKey(count + 1)) {
                freqList.put(count + 1, new DoublyLinkedList());
            }
            freqList.get(count + 1).addNode(node);
            return;
        }
        if (size == capacity) {
            Node lru = freqList.get(minCount).removeHead();
            cache.remove(lru.key);
            size--;
        }
        Node node = new Node(key, value);
        cache.put(key, node);
        if (!freqList.containsKey(1)) {
            freqList.put(1, new DoublyLinkedList());
        }
        freqList.get(1).addNode(node);
        minCount = 1;
        size++;
    }

    private int capacity;
    private int size;
    private int minCount;
    private Map<Integer, Node> cache;
    private Map<Integer, DoublyLinkedList> freqList;
    private Map<Integer, DoublyLinkedList> freqMap;
}
